import{_ as s,o as a,c as n,U as e}from"./chunks/framework.adbdbaa5.js";const h=JSON.parse('{"title":"小程序学习记录——单元测试","description":"","frontmatter":{"layout":"blog","title":"小程序学习记录——单元测试","date":"2022-08-09T11:01:43.081Z"},"headers":[],"relativePath":"mini-apps/小程序学习记录——单元测试.md","filePath":"mini-apps/小程序学习记录——单元测试.md"}'),t={name:"mini-apps/小程序学习记录——单元测试.md"},l=e(`<p>初识单元测试</p><h3 id="为什么要进行单元测试" tabindex="-1">为什么要进行单元测试 <a class="header-anchor" href="#为什么要进行单元测试" aria-label="Permalink to &quot;为什么要进行单元测试&quot;">​</a></h3><p>JavaScript 缺少类型检查，编译期间无法定位到错误，单元测试可以测试多种异常情况。单元测试也支持重构（重构就是在不改变软件系统外部行为的前提下，改善它的内部结构）。</p><h3 id="测试流程" tabindex="-1">测试流程 <a class="header-anchor" href="#测试流程" aria-label="Permalink to &quot;测试流程&quot;">​</a></h3><ol><li>初始化小程序项目，编写待测试组件</li><li>安装jest,miniprogram-simulate测试环境</li><li>编写测试用例</li><li>执行测试</li></ol><h3 id="测试框架" tabindex="-1">测试框架 <a class="header-anchor" href="#测试框架" aria-label="Permalink to &quot;测试框架&quot;">​</a></h3><p>安装jest相关依赖</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#A6ACCD;">npm install -D jest babel-jest babel-core babel-preset-env regenerator-runtime</span></span></code></pre></div><p>Jest是 Facebook 的一套开源的 JavaScript 测试框架， 它自动集成了断言、JSDom、覆盖率报告等开发者所需要的所有测试工具，是一款几乎零配置的测试框架。</p><p>安装测试工具集:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#A6ACCD;">npm i --save-dev miniprogram-simulate</span></span></code></pre></div><p>编辑package.json，在scripts新建test命令。</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#A6ACCD;">&quot;scripts&quot;: {</span></span>
<span class="line"><span style="color:#A6ACCD;">        &quot;test&quot;: &quot;jest --coverage&quot;</span></span>
<span class="line"><span style="color:#A6ACCD;">    },</span></span></code></pre></div><h3 id="断言" tabindex="-1">断言 <a class="header-anchor" href="#断言" aria-label="Permalink to &quot;断言&quot;">​</a></h3><p>javascrpt内置断言方法只有一个：console.assets。 我们通常选择第三方断言库来满足需求，比如jest断言库。</p><h4 id="常用的jest断言" tabindex="-1">常用的jest断言 <a class="header-anchor" href="#常用的jest断言" aria-label="Permalink to &quot;常用的jest断言&quot;">​</a></h4><p><strong>toBe</strong> 最简单的测试值的方法是看是否精确匹配。</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#A6ACCD;">test(&#39;two plus two is four&#39;, () =&gt; { </span></span>
<span class="line"><span style="color:#A6ACCD;">    expect(2 + 2).toBe(4); </span></span>
<span class="line"><span style="color:#A6ACCD;">});</span></span></code></pre></div><p><strong>toEqual</strong> .toEqual匹配器会递归的检查对象所有属性和属性值是否相等，所以如果要进行应用类型的比较时，请使用.toEqual匹配器而不是.toBe。</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#A6ACCD;">test(&#39;object assignment&#39;, () =&gt; { </span></span>
<span class="line"><span style="color:#A6ACCD;">    const data = {one: 1}; </span></span>
<span class="line"><span style="color:#A6ACCD;">    data[&#39;two&#39;] = 2; </span></span>
<span class="line"><span style="color:#A6ACCD;">     expect(data).toEqual({one: 1, two: 2}); </span></span>
<span class="line"><span style="color:#A6ACCD;">});</span></span></code></pre></div><p><strong>.not</strong> 用来测试相反的用例</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#A6ACCD;">import functions  from &#39;../src/functions&#39;</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span>
<span class="line"><span style="color:#A6ACCD;">test(&#39;sum(2, 2) 不等于 5&#39;, () =&gt; {</span></span>
<span class="line"><span style="color:#A6ACCD;">  expect(functions.sum(2, 2)).not.toBe(5);</span></span>
<span class="line"><span style="color:#A6ACCD;">})</span></span></code></pre></div><p><strong>.toHaveLength</strong> 可以很方便的用来测试字符串和数组类型的长度是否满足预期。</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#A6ACCD;">import functions  from &#39;../src/functions&#39;;</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span>
<span class="line"><span style="color:#A6ACCD;">test(&#39;getIntArray(3)返回的数组长度应该为3&#39;, () =&gt; {</span></span>
<span class="line"><span style="color:#A6ACCD;">  expect(functions.getIntArray(3)).toHaveLength(3);</span></span>
<span class="line"><span style="color:#A6ACCD;">})</span></span></code></pre></div><h3 id="mock函数" tabindex="-1">mock函数 <a class="header-anchor" href="#mock函数" aria-label="Permalink to &quot;mock函数&quot;">​</a></h3><p>在项目中，一个模块的方法内常常会去调用另外一个模块的方法。在单元测试中，我们可能并不需要关心内部调用的方法的执行过程和结果，只想知道它是否被正确调用即可，甚至会指定该函数的返回值。</p><p><strong>mock函数功能</strong></p><ul><li>捕获函数调用情况</li><li>设置函数返回值</li><li>改变函数的内部实现</li></ul><h3 id="编写测试用例" tabindex="-1">编写测试用例 <a class="header-anchor" href="#编写测试用例" aria-label="Permalink to &quot;编写测试用例&quot;">​</a></h3><p>在项目根目录下创建test目录，并在test目录下创建测试名.test.js文件。Jest会自动找到项目中所有使用.spec.js或.test.js文件命名的测试文件并执行。</p><p>官方文档用例：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#A6ACCD;">// /test/components/index.test.js</span></span>
<span class="line"><span style="color:#A6ACCD;">const simulate = require(&#39;miniprogram-simulate&#39;)</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span>
<span class="line"><span style="color:#A6ACCD;">test(&#39;components/index&#39;, () =&gt; {</span></span>
<span class="line"><span style="color:#A6ACCD;">    const id = simulate.load(&#39;/components/index&#39;) // 此处必须传入绝对路径</span></span>
<span class="line"><span style="color:#A6ACCD;">    const comp = simulate.render(id) // 渲染成自定义组件树实例</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span>
<span class="line"><span style="color:#A6ACCD;">    const parent = document.createElement(&#39;parent-wrapper&#39;) // 创建父亲节点</span></span>
<span class="line"><span style="color:#A6ACCD;">    comp.attach(parent) // attach 到父亲节点上，此时会触发自定义组件的 attached 钩子</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span>
<span class="line"><span style="color:#A6ACCD;">    const view = comp.querySelector(&#39;.index&#39;) // 获取子组件 view</span></span>
<span class="line"><span style="color:#A6ACCD;">    expect(view.dom.innerHTML).toBe(&#39;index.properties&#39;) // 测试渲染结果</span></span>
<span class="line"><span style="color:#A6ACCD;">    expect(window.getComputedStyle(view.dom).color).toBe(&#39;green&#39;) // 测试渲染结果</span></span>
<span class="line"><span style="color:#A6ACCD;">})</span></span></code></pre></div><h3 id="运行测试" tabindex="-1">运行测试 <a class="header-anchor" href="#运行测试" aria-label="Permalink to &quot;运行测试&quot;">​</a></h3><p>使用npm run test</p><p>###参考链接 <a href="https://www.jianshu.com/p/ae652d0b8fc5" target="_blank" rel="noreferrer">使用Jest测试JavaScript</a></p>`,35),p=[l];function o(c,i,r,d,C,u){return a(),n("div",null,p)}const m=s(t,[["render",o]]);export{h as __pageData,m as default};
